@* Displays a single product: image placeholder, name, price, rating, stock badge, add-to-cart *@

<div class="card h-100 product-card" role="button" @onclick="HandleCardClick">
    <div class="card-img-top product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-primary fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@($"{Product.Rating:F1} out of 5")">
            @RenderStars(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string RenderStars(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.2s ease;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-3">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>
            @for (int i = 1; i <= TotalPages; i++)
            {
                var pageNum = i;
                <li class="page-item @(pageNum == Page ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <h3 class="mb-3">Product Catalog</h3>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger" role="alert">
            <strong>Error:</strong> @errorMessage
            <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
        </div>
    }
    else
    {
        <div class="row">
            @* Sidebar *@
            <div class="col-md-3">
                <CatalogFilters Categories="categories" OnFilterApplied="HandleFilterApplied" />
            </div>

            @* Main content *@
            <div class="col-md-9">
                <CatalogToolbar SortBy="@sortBy"
                                TotalCount="@totalCount"
                                Page="@currentPage"
                                PageSize="@pageSize"
                                OnSortChanged="HandleSortChanged" />

                @if (isLoading)
                {
                    <div class="d-flex justify-content-center py-5">
                        <div class="spinner-border text-primary" role="status">
                            <span class="visually-hidden">Loading...</span>
                        </div>
                    </div>
                }
                else if (products.Count == 0)
                {
                    <div class="alert alert-info text-center" role="alert">
                        No products found. Try adjusting your filters.
                    </div>
                }
                else
                {
                    <ProductGrid Products="products"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }

                <CatalogPagination Page="@currentPage"
                                   TotalCount="@totalCount"
                                   PageSize="@pageSize"
                                   OnPageChanged="HandlePageChanged" />
            </div>
        </div>
    }
</div>

@code {
    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private int totalCount;
    private bool isLoading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            var result = await productsTask;
            products = result.Items;
            totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            products = result.Items;
            totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            errorMessage = $"Search failed. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadInitialData();
    }
}

